import math

RING_RADIUS_MM = 770  # example mini-sumo ring
EDGE_TH = 0.4

class SumoBot:
    def __init__(self):
        self.state = 'SEEK'
        self.t = 0.0

    def tick(self, dt, border_sensors, opponent_bearing_deg, opponent_dist):
        if any(s < EDGE_TH for s in border_sensors):
            self.state = 'EDGE_ESCAPE'
            return self.edge_escape()
        if self.state == 'SEEK' and opponent_dist < 400:
            self.state = 'CHARGE'
        if self.state == 'CHARGE':
            return self.drive_toward(opponent_bearing_deg)
        return self.scan_rotate(dt)

    def edge_escape(self):
        return (-0.7, -0.7), 0.35  # reverse, then curve (implement in drive)
